module top_module(
input  wire clk,
input  wire rst,
output wire [3:0] count
);reg [3:0] counter_reg;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt)
    if (rst)
        counter_reg <= 4'b0000;
    else
        counter_reg <= counter_reg + 1;

assign count = counter_reg;

endmodule
